namespace sv_0e6a607035614ffabd6b60816b945198.Services;

/// <summary>
/// Scoped service (per-circuit) that holds the current warehouse selection.
/// Because it's scoped, each Blazor Server circuit gets its own instance,
/// ensuring user isolation. Interactive components inject this to cross the
/// static layout ↔ interactive component render-mode boundary.
/// </summary>
public class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — Central"),
        ("WH-004", "Warehouse D — South"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId).Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_0e6a607035614ffabd6b60816b945198.Services;

/// <summary>
/// Scoped service that simulates checking low-stock inventory counts.
/// Exposes an event so all subscribed components (alert badges, dashboard)
/// update together when new data arrives — regardless of parent-child relationships.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Fired whenever new alert data is available. All subscribers should
    /// call StateHasChanged when they receive this event.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>Simulates a database query returning a random count 0–15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Polls for low-stock count and notifies all subscribers.
    /// Called by the component that owns the polling timer.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }
}

@rendermode InteractiveServer
@using sv_0e6a607035614ffabd6b60816b945198.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector px-3 py-2">
    <label class="form-label text-light mb-1 small">Current Warehouse</label>
    <select class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseStateService.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@using sv_0e6a607035614ffabd6b60816b945198.Services
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="alert-badge-wrapper">
    @ChildContent
    @if (AlertService.LatestLowStockCount > 0)
    {
        <span class="badge rounded-pill bg-danger alert-badge">
            @AlertService.LatestLowStockCount
        </span>
    }
</span>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnAlertDataChanged;
    }

    private async Task OnAlertDataChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnAlertDataChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_0e6a607035614ffabd6b60816b945198.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Selected Warehouse</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouseName</p>
                <small class="text-muted">@WarehouseState.CurrentWarehouseId</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(_lowStockCount > 5 ? "border-danger" : _lowStockCount > 0 ? "border-warning" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Low-Stock Alerts</h5>
                <p class="display-3 @(_lowStockCount > 5 ? "text-danger" : _lowStockCount > 0 ? "text-warning" : "text-success")">
                    @_lowStockCount
                </p>
                <small class="text-muted">items below minimum level</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Polling Status</h5>
                <p class="display-6">
                    @if (_isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-secondary">○ Paused</span>
                    }
                </p>
                <small class="text-muted">refreshes every 10 s</small>
            </div>
        </div>
    </div>
</div>

<div class="mt-4">
    <h4>Recent Activity</h4>
    <ul class="list-group">
        @foreach (var entry in _logEntries)
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @entry.Message
                <span class="badge bg-primary rounded-pill">@entry.Count</span>
            </li>
        }
        @if (_logEntries.Count == 0)
        {
            <li class="list-group-item text-muted">Waiting for first poll…</li>
        }
    </ul>
</div>

@code {
    private int _lowStockCount;
    private bool _isPolling;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private readonly List<LogEntry> _logEntries = [];

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertDataChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse changed — restart polling for the new warehouse
        StopPolling();
        _logEntries.Clear();
        await InvokeAsync(async () =>
        {
            await StartPollingAsync();
            StateHasChanged();
        });
    }

    private async Task OnAlertDataChanged()
    {
        _lowStockCount = AlertService.LatestLowStockCount;
        await InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _isPolling = true;

        // Initial fetch
        await PollOnceAsync();

        // Background loop
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () =>
                {
                    await PollOnceAsync();
                    StateHasChanged();
                });
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / warehouse change
        }
    }

    private async Task PollOnceAsync()
    {
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _lowStockCount = AlertService.LatestLowStockCount;

        _logEntries.Insert(0, new LogEntry(
            $"[{DateTime.Now:HH:mm:ss}] Polled {WarehouseState.CurrentWarehouseName}",
            _lowStockCount));

        // Keep last 10 entries
        if (_logEntries.Count > 10)
            _logEntries.RemoveAt(_logEntries.Count - 1);
    }

    private void StopPolling()
    {
        _isPolling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertDataChanged;
        StopPolling();
    }

    private record LogEntry(string Message, int Count);
}

