+            <li class="list-group-item text-muted">Waiting for first poll…</li>
+        }
+    </ul>
+</div>
+
+@code {
+    private int _lowStockCount;
+    private bool _isPolling;
+    private PeriodicTimer? _timer;
+    private CancellationTokenSource? _cts;
+    private readonly List<LogEntry> _logEntries = [];
+
+    protected override void OnInitialized()
+    {
+        WarehouseState.OnChange += OnWarehouseChanged;
+        AlertService.OnAlertCountChanged += OnAlertDataChanged;
+    }
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            await StartPollingAsync();
+        }
+    }
+
+    private async void OnWarehouseChanged()
+    {
+        // Warehouse changed — restart polling for the new warehouse
+        StopPolling();
+        _logEntries.Clear();
+        await InvokeAsync(async () =>
+        {
+            await StartPollingAsync();
+            StateHasChanged();
+        });
+    }
+
+    private async Task OnAlertDataChanged()
+    {
+        _lowStockCount = AlertService.LatestLowStockCount;
+        await InvokeAsync(StateHasChanged);
+    }
+
+    private async Task StartPollingAsync()
+    {
+        _cts = new CancellationTokenSource();
+        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
+        _isPolling = true;
+
+        // Initial fetch
+        await PollOnceAsync();
+
+        // Background loop
+        _ = PollLoopAsync(_cts.Token);
+    }
+
+    private async Task PollLoopAsync(CancellationToken ct)
+    {
+        try
+        {
+            while (await _timer!.WaitForNextTickAsync(ct))
+            {
+                await InvokeAsync(async () =>
+                {
+                    await PollOnceAsync();
+                    StateHasChanged();
+                });
+            }
+        }
+        catch (OperationCanceledException)
+        {
+            // Expected on dispose / warehouse change
+        }
+    }
+
+    private async Task PollOnceAsync()
+    {
+        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
+        _lowStockCount = AlertService.LatestLowStockCount;
+
+        _logEntries.Insert(0, new LogEntry(
+            $"[{DateTime.Now:HH:mm:ss}] Polled {WarehouseState.CurrentWarehouseName}",
+            _lowStockCount));
+
+        // Keep last 10 entries
+        if (_logEntries.Count > 10)
+            _logEntries.RemoveAt(_logEntries.Count - 1);
+    }
+
+    private void StopPolling()
+    {
+        _isPolling = false;
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = null;
+        _timer?.Dispose();
+        _timer = null;
+    }
+
+    public void Dispose()
+    {
+        WarehouseState.OnChange -= OnWarehouseChanged;
+        AlertService.OnAlertCountChanged -= OnAlertDataChanged;
+        StopPolling();
+    }
+
+    private record LogEntry(string Message, int Count);
+}
+

